import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.BbyMWZAR.js";const p=JSON.parse('{"title":"React 事件机制：合成事件、事件委托与事件池","description":"","frontmatter":{"title":"React 事件机制：合成事件、事件委托与事件池","difficulty":"medium","tags":["SyntheticEvent","事件委托","事件池","React 17"],"estimate":20},"headers":[],"relativePath":"domains/react/qa/12-event-system.md","filePath":"domains/react/qa/12-event-system.md","lastUpdated":1783504823000}'),i={name:"domains/react/qa/12-event-system.md"};function s(r,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="问答题-12-进阶-react-事件机制-合成事件、事件委托与事件池" tabindex="-1">问答题 12（进阶）：React 事件机制：合成事件、事件委托与事件池 <a class="header-anchor" href="#问答题-12-进阶-react-事件机制-合成事件、事件委托与事件池" aria-label="Permalink to &quot;问答题 12（进阶）：React 事件机制：合成事件、事件委托与事件池&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>React 里 <code>onClick={handler}</code> 和原生 DOM 的 <code>element.addEventListener(&quot;click&quot;, handler)</code> 有什么区别？请解释「合成事件」（SyntheticEvent）、「事件委托」的实现，以及 React 17 前后关于「事件池」的变化。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><h3 id="合成事件-syntheticevent" tabindex="-1">合成事件（SyntheticEvent） <a class="header-anchor" href="#合成事件-syntheticevent" aria-label="Permalink to &quot;合成事件（SyntheticEvent）&quot;">​</a></h3><ul><li>React 把浏览器的原生事件对象包了一层，统一成 <code>SyntheticEvent</code> 对象。</li><li>目的： <ol><li><strong>跨浏览器兼容</strong>：抹平不同浏览器的事件属性差异（如 <code>event.target</code> vs <code>event.srcElement</code>）。</li><li><strong>一致的接口</strong>：<code>stopPropagation</code> / <code>preventDefault</code> / <code>nativeEvent</code>（原生事件对象）等 API 统一。</li><li><strong>性能</strong>：早期版本还用了「事件池」复用对象（后来移除）。</li></ol></li><li>拿到原生事件：<code>event.nativeEvent</code>。</li></ul><h3 id="事件委托-react-17-前后的差异" tabindex="-1">事件委托：React 17 前后的差异 <a class="header-anchor" href="#事件委托-react-17-前后的差异" aria-label="Permalink to &quot;事件委托：React 17 前后的差异&quot;">​</a></h3><p><strong>React 16 及以前</strong></p><ul><li>React 把<strong>所有支持的事件类型</strong>（click、change、keydown 等）都挂到了 <strong><code>document</code></strong> 上。</li><li>组件里写 <code>onClick</code>，本质是把回调登记到 React 内部的 map，然后 document 上的统一监听器根据 event.target 冒泡路径找到对应组件的回调依次触发。</li></ul><p><strong>React 17 及以后</strong></p><ul><li>事件委托的容器改为 <strong>React 应用的根节点</strong>（<code>ReactDOM.render</code> / <code>createRoot</code> 挂载的那个 DOM 节点），不再全局挂 document。</li><li>好处： <ol><li><strong>多版本 React 共存</strong>：微前端场景下，一个页面挂载了 React 17 的子应用和 React 16 的主应用，事件不会互相污染。</li><li><strong>可以在 React 应用外</strong>（比如挂在 document 上的原生监听器）用 <code>e.stopPropagation()</code> 阻止 React 应用内的合成事件触发（因为冒泡还没到根节点）。</li><li><strong>更容易集成非 React 页面</strong>（比如 legacy jQuery 页面）。</li></ol></li></ul><h3 id="触发顺序" tabindex="-1">触发顺序 <a class="header-anchor" href="#触发顺序" aria-label="Permalink to &quot;触发顺序&quot;">​</a></h3><p>在同一个元素上同时挂了原生和合成事件时，触发顺序（React 17+，事件委托到 root）：</p><ol><li>原生<strong>捕获</strong>阶段（原生 addEventListener 的 capture）</li><li>合成<strong>捕获</strong>阶段（React 的 <code>onClickCapture</code>）</li><li>原生冒泡阶段（原生 addEventListener bubble）——<strong>在 root 之下的原生监听器先跑</strong></li><li>合成冒泡阶段（React 的 <code>onClick</code>）——冒泡到 root 时 React 处理</li><li>原生冒泡阶段（root 之上的 document）</li></ol><p>React 16 由于事件挂在 document 上，合成事件<strong>总是在原生事件之后</strong>触发；React 17 之后顺序更贴合直觉。</p><h3 id="事件池-event-pool-——-已移除" tabindex="-1">事件池（Event Pool）—— 已移除 <a class="header-anchor" href="#事件池-event-pool-——-已移除" aria-label="Permalink to &quot;事件池（Event Pool）—— 已移除&quot;">​</a></h3><ul><li><strong>React 16 及以前</strong>存在事件池：<code>SyntheticEvent</code> 对象被复用，事件处理结束后对象的所有属性会被置空（<code>nullify</code>），以节省 GC 开销。</li><li>副作用：<strong>不能异步访问 event 的属性</strong>：</li></ul><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// React 16 里的坑</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> handler</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  setTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(e.type)); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// null / undefined，因为对象已被回收</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>解决方案：<code>e.persist()</code> 保留对象，或在同步阶段解构出需要的字段。</li><li><strong>React 17+ 移除了事件池</strong>：现代浏览器 GC 已经足够快，池化收益不明显，反而增加了心智负担。现在异步访问 event 也是安全的，<code>e.persist()</code> 保留但不再需要。</li></ul><h3 id="支持的事件与命名规则" tabindex="-1">支持的事件与命名规则 <a class="header-anchor" href="#支持的事件与命名规则" aria-label="Permalink to &quot;支持的事件与命名规则&quot;">​</a></h3><ul><li>React 用 camelCase：<code>onClick</code>、<code>onChange</code>、<code>onMouseEnter</code>。</li><li>内置事件很多，但<strong>不包括所有原生事件</strong>（如 <code>onCopy</code> 支持，但某些冷门事件仍需 <code>addEventListener</code>）。</li><li>冒泡：默认冒泡触发 <code>onXxx</code>；<code>onXxxCapture</code> 是捕获阶段。</li><li><strong>不支持自定义事件冒泡</strong>：<code>element.dispatchEvent(new CustomEvent(...))</code> 不会触发 React 的合成事件（原生冒泡到 root 时 React 不认识这个类型）。</li></ul><h2 id="追问-1-为什么-onchange-在-react-里和原生-change-事件行为不一样" tabindex="-1">追问 1：为什么 <code>onChange</code> 在 React 里和原生 <code>change</code> 事件行为不一样？ <a class="header-anchor" href="#追问-1-为什么-onchange-在-react-里和原生-change-事件行为不一样" aria-label="Permalink to &quot;追问 1：为什么 `onChange` 在 React 里和原生 `change` 事件行为不一样？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>原生 <code>change</code> 事件在 input 失焦时才触发；React 的 <code>onChange</code> <strong>每次输入都会触发</strong>，等价于原生的 <code>input</code> 事件。</li><li>原因：React 官方觉得原生的 change 语义不够直观，统一改成了「每次值变化就触发」。</li><li>想要类似原生的 change 行为（失焦触发），用 <code>onBlur</code>。</li><li><code>onInput</code> 也存在，与 <code>onChange</code> 行为几乎等价，实际用哪个都行——<strong>React 内部对二者都做了 polyfill</strong>（其实内部都是监听原生 <code>input</code> + 值变化）。</li></ul><h2 id="追问-2-react-合成事件的-stoppropagation-能阻止原生事件冒泡吗-反之呢" tabindex="-1">追问 2：React 合成事件的 <code>stopPropagation</code> 能阻止原生事件冒泡吗？反之呢？ <a class="header-anchor" href="#追问-2-react-合成事件的-stoppropagation-能阻止原生事件冒泡吗-反之呢" aria-label="Permalink to &quot;追问 2：React 合成事件的 `stopPropagation` 能阻止原生事件冒泡吗？反之呢？&quot;">​</a></h2><p><strong>答</strong>：情况分两个方向：</p><ul><li><strong>合成事件的 <code>stopPropagation</code> → 阻止合成事件的进一步冒泡</strong>（不再触发上层组件的 <code>onClick</code>），但<strong>已经触发的原生冒泡阻止不了</strong>。因为 React 17+ 是在原生事件冒泡到 root 时才开始处理合成事件；此时原生事件已经从子元素冒泡到 root。</li><li>但你可以<strong>同时调 <code>e.nativeEvent.stopPropagation()</code></strong>：阻止 root 之上的原生监听器接收事件。</li><li>反过来：<strong>原生事件的 <code>stopPropagation</code> 能阻止 React 合成事件触发</strong>（React 17+），因为原生事件冒泡被打断就到不了 root，也就走不到合成事件处理逻辑。这在 React 16 是不行的（当时 React 挂 document，绕不过去）。</li><li>这个改动实际上是<strong>破坏性的</strong>——某些 React 16 时代能用的 hack 在 17 之后失效。</li></ul><h2 id="追问-3-为什么-react-事件不用-addeventlistener-直接挂在每个-dom-节点上-事件委托的收益是什么" tabindex="-1">追问 3：为什么 React 事件不用 <code>addEventListener</code> 直接挂在每个 DOM 节点上？事件委托的收益是什么？ <a class="header-anchor" href="#追问-3-为什么-react-事件不用-addeventlistener-直接挂在每个-dom-节点上-事件委托的收益是什么" aria-label="Permalink to &quot;追问 3：为什么 React 事件不用 `addEventListener` 直接挂在每个 DOM 节点上？事件委托的收益是什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>性能</strong>：假设列表有 1000 个 item，都要监听 click，直接绑定意味着注册 1000 个 listener（大量内存 + 慢）。事件委托只绑定 1 个 listener 到父级，靠冒泡机制路由。</li><li><strong>动态节点</strong>：新加入的 DOM 节点自动被父级监听覆盖，无需再手动 addEventListener。</li><li><strong>一致性</strong>：React 用同一套内部管道处理所有事件，方便实现批处理（React 17-）、Concurrent 模式下的事件优先级、SSR hydration。</li><li><strong>成本</strong>：需要维护「component → handler」的 map；<code>stopPropagation</code> 语义要额外实现（因为冒泡阶段是模拟的）。</li><li>现代前端框架（Vue、Svelte 等）大多<strong>不做全局事件委托</strong>，直接在每个 DOM 上绑。React 的选择更多是<strong>历史 + 与 Fiber 调度整合方便</strong>。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/responding-to-events" target="_blank" rel="noreferrer">React: Responding to Events</a>：合成事件与事件处理函数写法</li><li><a href="https://react.dev/learn/adding-interactivity" target="_blank" rel="noreferrer">React: Adding Interactivity</a>：事件与状态更新在交互流中的配合</li><li><a href="https://legacy.reactjs.org/blog/2020/10/20/react-v17.html#changes-to-event-delegation" target="_blank" rel="noreferrer">React 17 Release Notes</a>：事件委托从 <code>document</code> 迁至根节点的变更</li></ul>',33)])])}const u=t(i,[["render",s]]);export{p as __pageData,u as default};
